  if (!capability) return null;
  if (capability.intendedModes.includes(mode)) {
    const lensDisabledReason = lensDisabledReasonForCommand(commandId, lensMode);
    if (lensDisabledReason) {
      return {
        state: 'disabled',
        capability,
        reason: lensDisabledReason,
